/* ------------------------------------------------------------------
   Small Sparkline Charts
------------------------------------------------------------------ */
function renderSparkline(selector, color, label) {
    new ApexCharts(document.querySelector(selector), {
        chart: {
            type: "area",
            height: 100,
            sparkline: { enabled: true },
            toolbar: { show: false }
        },
        series: [
            {
                name: label,
                data: [44, 55, 41, 60, 52, 66, 51]
            }
        ],
        stroke: {
            width: 2,
            curve: "smooth"
        },
        fill: {
            type: "gradient",
            gradient: {
                shadeIntensity: 1,
                opacityFrom: 0.2,
                opacityTo: 0.75,
                stops: [0, 90, 100]
            }
        },
        colors: [color],
        dataLabels: { enabled: false },
        grid: { show: false },
        tooltip: {
            y: {
                formatter: value => `${value} ${label}`
            },
            style: {
                fontSize: "12px",
                fontFamily: "Inter"
            }
        }
    }).render();
}

$(document).ready(function () {
    renderSparkline("#task-completed-area-chart", "#3454d1", "Tasks");
    renderSparkline("#new-tasks-area-chart", "#25b865", "Projects");
    renderSparkline("#project-done-area-chart", "#d13b4c", "Projects");
});


